/**
 * First step in the repair pipeline — diagnoses problems and creates a repair session
 * @summary Run repair diagnosis
 */
export const claudeRepairDiagnoseBodyScopeDefault = `full`;

export const ClaudeRepairDiagnoseBody = zod.object({
  scope: zod
    .enum([
      "full",
      "modules",
      "entities",
      "fields",
      "relations",
      "forms",
      "views",
      "actions",
      "statuses",
      "details",
      "buttons",
      "menus",
      "permissions",
    ])
    .default(claudeRepairDiagnoseBodyScopeDefault),
});

export const ClaudeRepairDiagnoseResponse = zod.object({
  sessionId: zod.string().optional(),
  scope: zod.string().optional(),
  totalDiagnoses: zod.number().optional(),
  diagnoses: zod
    .array(
      zod.object({
        id: zod.string().optional(),
        objectType: zod.string().optional(),
        objectId: zod.number().optional(),
        objectName: zod.string().optional(),
        problem: zod.string().optional(),
        severity: zod.string().optional(),
      }),
    )
    .optional(),
});

/**
 * Second step — generates repair proposals for diagnosed problems
 * @summary Generate repair proposals
 */
export const ClaudeRepairProposeBody = zod.object({
  sessionId: zod.string(),
  diagnosisIds: zod.array(zod.string()).optional(),
});

export const ClaudeRepairProposeResponse = zod.object({
  sessionId: zod.string().optional(),
  totalProposals: zod.number().optional(),
  safeCount: zod.number().optional(),
  unsafeCount: zod.number().optional(),
  proposals: zod
    .array(
      zod.object({
        diagnosisId: zod.string().optional(),
        repairType: zod.string().optional(),
        description: zod.string().optional(),
        actions: zod
          .array(
            zod.object({
              operation: zod.enum(["insert", "update", "delete"]).optional(),
              table: zod.string().optional(),
              targetId: zod.number().nullish(),
              changes: zod.record(zod.string(), zod.unknown()).optional(),
            }),
          )
          .optional(),
        safe: zod.boolean().optional(),
        reversible: zod.boolean().optional(),
      }),
    )
    .optional(),
});

/**
 * Third step — validates that proposed repairs are safe to apply
 * @summary Validate repair proposals
 */
export const ClaudeRepairValidateBody = zod.object({
  sessionId: zod.string(),
  diagnosisIds: zod.array(zod.string()).optional(),
});

export const ClaudeRepairValidateResponse = zod.object({
  sessionId: zod.string().optional(),
  totalValidated: zod.number().optional(),
  totalRejected: zod.number().optional(),
  validations: zod
    .array(
      zod.object({
        diagnosisId: zod.string().optional(),
        repairType: zod.string().optional(),
        valid: zod.boolean().optional(),
        reason: zod.string().optional(),
      }),
    )
    .optional(),
});

/**
 * Final step — applies validated repair proposals. Only validated proposals can be applied.
 * @summary Apply validated repairs
 */
